pub fn get_current_provider() -> Result<Option<String>, AppError> {
    let config = read_iiagent_config()?;
    Ok(config
        .get("_app_ii-agent")
        .and_then(|v| v.get("current_provider"))
        .and_then(|v| v.as_str())
        .map(|s| s.to_string()))
}

